import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, SupplementLog, DailyTargets, SupplementInfo } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getComplementaryAdvice = async (
  supplementName: string,
  userProfile: UserProfile
): Promise<string> => {
  try {
    const prompt = `
      Actúa como un nutricionista deportivo experto.
      El usuario (${userProfile.weight}kg, objetivo: ${userProfile.goal}) está tomando ${supplementName}.

      1. ¿Qué otros suplementos o alimentos complementan bien (sinergia) a ${supplementName}?
      2. ¿Hay alguna contraindicación común o consejo de absorción?

      Responde en español, sé conciso (máximo 100 palabras) y usa formato markdown simple.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    return response.text || "No se pudo generar un consejo en este momento.";
  } catch (error) {
    console.error("Error fetching advice:", error);
    return "Error al conectar con el asistente de IA.";
  }
};

export const getDailyAnalysis = async (
  profile: UserProfile,
  logs: SupplementLog[],
  targets: DailyTargets
): Promise<string> => {
  try {
    const logSummary = logs.map(l => `- ${l.name}: ${l.amount}${l.unit}`).join('\n');

    const prompt = `
      Analiza el registro de suplementos de hoy para este usuario:
      Perfil: ${profile.weight}kg, Objetivo: ${profile.goal}.
      Objetivos Calculados: Proteína ${targets.protein}g, Agua ${targets.water}L.

      Registro de hoy:
      ${logSummary}

      Proporciona un resumen breve y motivador (máximo 3 frases) sobre su progreso hoy y si falta algo crítico (especialmente hidratación si tomó creatina).
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    return response.text || "Análisis no disponible.";
  } catch (error) {
    console.error("Gemini analysis error:", error);
    return "No pudimos analizar tus datos en este momento.";
  }
};

export const getSupplementSafetyInfo = async (
  supplementName: string
): Promise<string> => {
  try {
    const prompt = `
      Explica brevemente las precauciones de seguridad para el suplemento: "${supplementName}".

      Enfócate en:
      1. ¿Por qué requiere supervisión profesional o cuidado?
      2. Efectos secundarios principales (ej: presión arterial, riñones, insomnio).
      3. Contraindicaciones clave.

      Responde en Español. Máximo 80 palabras. Usa tono de advertencia médica amigable.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    return response.text || "Información de seguridad no disponible.";
  } catch (error) {
    console.error("Gemini safety info error:", error);
    return "Error consultando información de seguridad.";
  }
};

export const estimateFoodProtein = async (
  foodDescription: string
): Promise<number> => {
  try {
    // Use structured JSON output for reliable number extraction
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Analiza la siguiente comida y estima la cantidad total de proteína en gramos: "${foodDescription}". Si no es comida o no puedes estimar, devuelve 0.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            grams: {
              type: Type.NUMBER,
              description: "Estimated protein amount in grams",
            },
          },
        },
      },
    });

    if (response.text) {
      const data = JSON.parse(response.text);
      return data.grams || 0;
    }
    return 0;
  } catch (error) {
    console.error("Protein estimation error:", error);
    return 0;
  }
};

export const analyzeCustomSupplement = async (
  name: string
): Promise<SupplementInfo | null> => {
  try {
    const prompt = `
      Genera información técnica para el suplemento deportivo: "${name}".
      Actúa como un prospecto médico/deportivo.

      Devuelve un JSON con:
      - name: Nombre oficial (capitalizado)
      - defaultAmount: Dosis recomendada estándar (número)
      - defaultUnit: Unidad de medida (mg, g, ml, scoop, caps)
      - description: Breve descripción de para qué sirve y cuidados principales (Max 15 palabras).
      - riskLevel: 'low', 'medium', o 'high' basado en seguridad general.
      - type: 'other' (o una categoría genérica).
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            defaultAmount: { type: Type.NUMBER },
            defaultUnit: { type: Type.STRING },
            description: { type: Type.STRING },
            riskLevel: { type: Type.STRING, enum: ['low', 'medium', 'high'] },
            type: { type: Type.STRING }
          },
          required: ["name", "defaultAmount", "defaultUnit", "description", "riskLevel"]
        }
      }
    });

    if (response.text) {
      const data = JSON.parse(response.text);
      return {
        id: `custom-${Date.now()}`,
        name: data.name,
        defaultAmount: data.defaultAmount,
        defaultUnit: data.defaultUnit,
        description: data.description,
        riskLevel: data.riskLevel as 'low' | 'medium' | 'high',
        type: data.type || 'other'
      };
    }
    return null;
  } catch (error) {
    console.error("Custom supplement analysis error:", error);
    return null;
  }
};

import React, { useState } from 'react';
import { UserProfile, Goal, ActivityLevel, AVAILABLE_SUPPLEMENTS, SupplementInfo } from '../types';
import { Save, User, AlertTriangle, Info, CheckCircle, X, Search, Sparkles, Plus } from 'lucide-react';
import { getSupplementSafetyInfo, analyzeCustomSupplement } from '../services/geminiService';

interface Props {
  profile: UserProfile;
  onSave: (profile: UserProfile) => void;
}

export const ProfileSettings: React.FC<Props> = ({ profile, onSave }) => {
  const [formData, setFormData] = useState<UserProfile>(profile);
  const [safetyInfo, setSafetyInfo] = useState<{name: string, info: string} | null>(null);
  const [loadingInfo, setLoadingInfo] = useState(false);

  // Custom Supplement State
  const [customSearch, setCustomSearch] = useState("");
  const [analyzingCustom, setAnalyzingCustom] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
  };

  const toggleSupplement = (id: string) => {
    const current = formData.activeSupplements || [];
    const updated = current.includes(id)
      ? current.filter(item => item !== id)
      : [...current, id];
    setFormData({ ...formData, activeSupplements: updated });
  };

  const handleGetSafetyInfo = async (e: React.MouseEvent, name: string) => {
    e.preventDefault(); // prevent form submit if inside form
    e.stopPropagation(); // prevent checkbox toggle
    setLoadingInfo(true);
    setSafetyInfo({ name, info: "Consultando especialista IA..." });

    const info = await getSupplementSafetyInfo(name);
    setSafetyInfo({ name, info });
    setLoadingInfo(false);
  };

  const handleAddCustomSupplement = async (e: React.MouseEvent) => {
    e.preventDefault();
    if (!customSearch.trim()) return;

    setAnalyzingCustom(true);
    const newSupp = await analyzeCustomSupplement(customSearch);
    setAnalyzingCustom(false);

    if (newSupp) {
      setFormData(prev => ({
        ...prev,
        customSupplements: [...(prev.customSupplements || []), newSupp],
        activeSupplements: [...(prev.activeSupplements || []), newSupp.id]
      }));
      setCustomSearch("");
    } else {
      alert("No pudimos analizar este suplemento. Intenta con otro nombre.");
    }
  };

  const removeCustomSupplement = (e: React.MouseEvent, id: string) => {
    e.preventDefault();
    e.stopPropagation();
    setFormData(prev => ({
      ...prev,
      customSupplements: (prev.customSupplements || []).filter(s => s.id !== id),
      activeSupplements: (prev.activeSupplements || []).filter(sid => sid !== id)
    }));
  };

  // Combine built-in and custom supplements for display
  const allSupplements = [
    ...AVAILABLE_SUPPLEMENTS,
    ...(formData.customSupplements || [])
  ];

  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 relative">
      <div className="flex items-center gap-2 mb-6 text-indigo-600">
        <User size={24} />
        <h2 className="text-xl font-bold">Configuración de Perfil</h2>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Basic Info Section */}
        <div className="space-y-4 border-b border-gray-100 pb-6">
          <h3 className="font-semibold text-gray-800">Datos Personales</h3>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Nombre</label>
            <input
              type="text"
              required
              value={formData.name}
              onChange={(e) => setFormData({ ...formData, name: e.target.value })}
              className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Peso (kg)</label>
              <input
                type="number"
                required
                min="30"
                max="300"
                value={formData.weight}
                onChange={(e) => setFormData({ ...formData, weight: parseFloat(e.target.value) })}
                className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Objetivo</label>
              <select
                value={formData.goal}
                onChange={(e) => setFormData({ ...formData, goal: e.target.value as Goal })}
                className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                <option value="muscle">Ganar Músculo</option>
                <option value="weight_loss">Perder Peso</option>
                <option value="maintenance">Mantenimiento</option>
              </select>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Nivel de Actividad</label>
              <select
                value={formData.activityLevel}
                onChange={(e) => setFormData({ ...formData, activityLevel: e.target.value as ActivityLevel })}
                className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                <option value="sedentary">Sedentario (Poco ejercicio)</option>
                <option value="moderate">Moderado (1-3 días/sem)</option>
                <option value="active">Activo (3-5 días/sem)</option>
                <option value="athlete">Atleta (6-7 días/sem)</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Meta de Sueño (horas)</label>
              <input
                type="number"
                min="4"
                max="12"
                step="0.5"
                value={formData.sleepGoal || 8}
                onChange={(e) => setFormData({ ...formData, sleepGoal: parseFloat(e.target.value) })}
                className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>
          </div>
        </div>

        {/* Supplement Stack Selection */}
        <div className="space-y-4">
          <div className="flex justify-between items-center">
            <h3 className="font-semibold text-gray-800 flex items-center gap-2">
              Mi Stack de Suplementos
              <span className="text-xs font-normal text-gray-500 bg-gray-100 px-2 py-0.5 rounded-full">Selecciona los que usas</span>
            </h3>
          </div>

          {/* Add Custom Supplement Input */}
          <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100">
             <label className="block text-sm font-medium text-indigo-900 mb-2">
               ¿No encuentras tu suplemento?
             </label>
             <div className="flex gap-2">
               <input 
                 type="text" 
                 placeholder="Ej: Ashwagandha, Citrulina..." 
                 value={customSearch}
                 onChange={(e) => setCustomSearch(e.target.value)}
                 className="flex-1 px-4 py-2 rounded-lg border border-indigo-200 focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
               />
               <button 
                 onClick={handleAddCustomSupplement}
                 disabled={analyzingCustom || !customSearch}
                 className="bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white px-4 py-2 rounded-lg font-medium text-sm flex items-center gap-2 transition-colors"
               >
                 {analyzingCustom ? <Sparkles size={16} className="animate-spin" /> : <Search size={16} />}
                 {analyzingCustom ? "Investigando..." : "Investigar y Agregar"}
               </button>
             </div>
             <p className="text-xs text-indigo-600/70 mt-2">
               <Sparkles size={12} className="inline mr-1" />
               La IA analizará el prospecto, dosis y riesgos automáticamente.
             </p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            {allSupplements.map((supp) => {
              const isActive = (formData.activeSupplements || []).includes(supp.id);
              const isRisky = supp.riskLevel === 'high';
              const isMedium = supp.riskLevel === 'medium';
              const isCustom = supp.id.startsWith('custom-');

              let borderClass = "border-gray-200";
              if (isActive) borderClass = "border-indigo-500 bg-indigo-50";
              if (isActive && isRisky) borderClass = "border-red-500 bg-red-50";
              if (isActive && isMedium) borderClass = "border-orange-400 bg-orange-50";

              return (
                <div 
                  key={supp.id}
                  onClick={() => toggleSupplement(supp.id)}
                  className={`relative p-3 rounded-lg border-2 cursor-pointer transition-all ${borderClass} hover:shadow-md group`}
