import React, { useMemo, useState } from 'react';
import { UserProfile, SupplementLog, DailyTargets, AVAILABLE_SUPPLEMENTS, SupplementInfo } from '../types';
import { Droplets, Dumbbell, Zap, Check, Sparkles, Utensils, GlassWater, Plus, Moon } from 'lucide-react';
import { getDailyAnalysis, estimateFoodProtein } from '../services/geminiService';

interface Props {
  profile: UserProfile;
  logs: SupplementLog[];
  targets: DailyTargets;
  onAddLog: (log: Omit<SupplementLog, 'id' | 'timestamp'>) => void;
}

export const Dashboard: React.FC<Props> = ({ profile, logs, targets, onAddLog }) => {
  const [aiAnalysis, setAiAnalysis] = useState<string>("");
  const [loadingAi, setLoadingAi] = useState(false);

  // Protein Widget State
  const [proteinMode, setProteinMode] = useState<'grams' | 'food'>('grams');
  const [proteinInput, setProteinInput] = useState("");
  const [foodInput, setFoodInput] = useState("");
  const [estimatingProtein, setEstimatingProtein] = useState(false);

  // Sleep Widget State
  const [sleepInput, setSleepInput] = useState("");

  // Merge built-in and custom supplements for lookup
  const allSupplements = useMemo(() => {
    return [...AVAILABLE_SUPPLEMENTS, ...(profile.customSupplements || [])];
  }, [profile.customSupplements]);

  // --- Calculations ---

  const todaysLogs = useMemo(() => {
    const today = new Date().setHours(0, 0, 0, 0);
    return logs.filter(l => l.timestamp >= today);
  }, [logs]);

  const totals = useMemo(() => {
    const protein = todaysLogs
      .filter(l => l.type === 'protein')
      .reduce((acc, curr) => acc + curr.amount, 0);

    const creatine = todaysLogs
      .filter(l => l.type === 'creatine')
      .reduce((acc, curr) => acc + curr.amount, 0);

    const waterMl = todaysLogs
      .filter(l => l.type === 'water')
      .reduce((acc, curr) => acc + curr.amount, 0);

    const sleep = todaysLogs
      .filter(l => l.type === 'sleep')
      .reduce((acc, curr) => acc + curr.amount, 0);

    return { protein, creatine, waterMl, sleep };
  }, [todaysLogs]);

  // Water Logic (Glasses)
  const glassSize = 200; // ml
  const recommendedWaterL = useMemo(() => {
    let base = targets.water;
    if (totals.creatine > 0) base += 0.5;
    return parseFloat(base.toFixed(1));
  }, [targets.water, totals.creatine]);

  const totalGlassesTarget = Math.ceil((recommendedWaterL * 1000) / glassSize);
  const glassesConsumed = Math.floor(totals.waterMl / glassSize);
  const glassesRemaining = Math.max(0, totalGlassesTarget - glassesConsumed);

  // --- Actions ---

  const handleGetAnalysis = async () => {
    setLoadingAi(true);
    const analysis = await getDailyAnalysis(profile, todaysLogs, { ...targets, water: recommendedWaterL });
    setAiAnalysis(analysis);
    setLoadingAi(false);
  };

  const addWaterGlass = () => {
    onAddLog({
      name: 'Agua',
      type: 'water',
      amount: glassSize,
      unit: 'ml'
    });
  };

  const toggleCreatine = () => {
    // Only allow adding, not removing via this simple toggle (simplifies logic)
    if (totals.creatine > 0) return; 

    const creatSupp = allSupplements.find(s => s.id === 'creat');
    if (creatSupp) {
      onAddLog({
        name: creatSupp.name,
        type: creatSupp.type,
        amount: creatSupp.defaultAmount,
        unit: creatSupp.defaultUnit
      });
    }
  };

  const handleAddSleep = () => {
    const hours = parseFloat(sleepInput);
    if (hours > 0) {
      onAddLog({
        name: 'Sueño',
        type: 'sleep',
        amount: hours,
        unit: 'h'
      });
      setSleepInput("");
    }
  };

  const handleProteinSubmit = async () => {
    if (proteinMode === 'grams') {
      const amount = parseFloat(proteinInput);
      if (amount > 0) {
        onAddLog({
          name: 'Proteína (Manual)',
          type: 'protein',
          amount,
          unit: 'g'
        });
        setProteinInput("");
      }
    } else {
      if (!foodInput) return;
      setEstimatingProtein(true);
      const estimated = await estimateFoodProtein(foodInput);
      setEstimatingProtein(false);

      if (estimated > 0) {
        const confirm = window.confirm(`Estimamos ${estimated}g de proteína para "${foodInput}". ¿Registrar?`);
        if (confirm) {
          onAddLog({
            name: `Comida: ${foodInput}`,
            type: 'protein',
            amount: estimated,
            unit: 'g'
          });
          setFoodInput("");
        }
      } else {
        alert("No pudimos estimar la proteína. Intenta ingresarlo manualmente.");
      }
    }
  };

  const handleGenericAdd = (suppId: string) => {
    const supp = allSupplements.find(s => s.id === suppId);
    if (supp) {
      onAddLog({
        name: supp.name,
        type: supp.type,
        amount: supp.defaultAmount,
        unit: supp.defaultUnit
      });
    }
  };

  // --- Render Widgets ---

  const renderActiveStack = () => {
    const activeIds = profile.activeSupplements || [];

    // Sort to put Protein and Creatine first if they exist
    const sortedStack = [...activeIds].sort((a, b) => {
      if (a === 'prot') return -1;
      if (b === 'prot') return 1;
      if (a === 'creat') return -1;
      if (b === 'creat') return 1;
      return 0;
    });

    return (
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">

        {/* WATER TRACKER (Always visible) */}
        <div className="bg-white p-5 rounded-xl shadow-sm border border-cyan-100 md:col-span-2 lg:col-span-1 relative overflow-hidden">
          <div className="flex justify-between items-start mb-4">
             <div>
                <h3 className="font-bold text-gray-800 flex items-center gap-2">
                  <Droplets className="text-cyan-500" size={20}/> Hidratación
                </h3>
                <p className="text-xs text-gray-500 mt-1">Meta: {recommendedWaterL}L ({totalGlassesTarget} vasos)</p>
             </div>
             <div className="text-right">
               <span className="text-2xl font-bold text-cyan-600">{glassesConsumed}</span>
               <span className="text-sm text-gray-400"> / {totalGlassesTarget}</span>
             </div>
          </div>

          <div className="flex flex-wrap gap-2 mb-4">
            {Array.from({ length: totalGlassesTarget }).map((_, i) => (
              <div 
                key={i} 
                className={`w-6 h-8 rounded-sm border flex items-end justify-center overflow-hidden transition-all ${
                  i < glassesConsumed ? 'border-cyan-500 bg-cyan-100' : 'border-gray-200 bg-gray-50'
                }`}
              >
                {i < glassesConsumed && <div className="w-full bg-cyan-400 h-full opacity-60"></div>}
              </div>
            ))}
          </div>

          <button 
            onClick={addWaterGlass}
            className="w-full bg-cyan-50 hover:bg-cyan-100 text-cyan-700 font-medium py-2 rounded-lg flex items-center justify-center gap-2 transition-colors"
          >
            <Plus size={16} /> Agregar Vaso (200cc)
          </button>

          {glassesRemaining > 0 && (
            <p className="text-center text-xs text-gray-400 mt-2">
              Faltan {glassesRemaining} vasos para tu meta
            </p>
          )}
        </div>

        {/* SLEEP WIDGET (Always visible) */}
        <div className="bg-white p-5 rounded-xl shadow-sm border border-indigo-900/10 md:col-span-1 relative overflow-hidden">
             <div className="flex justify-between items-start mb-4">
                <div>
                   <h3 className="font-bold text-gray-800 flex items-center gap-2">
                     <Moon className="text-indigo-900" size={20}/> Sueño
                   </h3>
                   <p className="text-xs text-gray-500 mt-1">Meta: {targets.sleep}h</p>
                </div>
                <div className="text-right">
                  <span className="text-2xl font-bold text-indigo-900">{totals.sleep}h</span>
                </div>
             </div>

             <div className="w-full bg-gray-100 rounded-full h-2.5 mb-4">
               <div 
                 className="bg-indigo-900 h-2.5 rounded-full" 
                 style={{ width: `${Math.min(100, (totals.sleep / targets.sleep) * 100)}%` }}
               ></div>
             </div>

             <div className="flex gap-2">
                <input 
                  type="number" 
                  step="0.5"
                  placeholder="Horas..."
                  value={sleepInput}
                  onChange={(e) => setSleepInput(e.target.value)}
                  className="flex-1 border border-gray-200 rounded-lg px-3 py-2 outline-none focus:border-indigo-500 text-sm"
                />
                <button 
                  onClick={handleAddSleep}
                  className="bg-indigo-900 hover:bg-indigo-800 text-white px-3 py-2 rounded-lg transition-colors"
                >
                  <Plus size={18} />
                </button>
             </div>
          </div>

        {/* Dynamic Supplements from Profile */}
        {sortedStack.map(suppId => {
          const supp = allSupplements.find(s => s.id === suppId);
          if (!supp) return null;

          // PROTEIN WIDGET
          if (suppId === 'prot') {
            const proteinLeft = Math.max(0, targets.protein - totals.protein);

            return (
              <div key={suppId} className="bg-white p-5 rounded-xl shadow-sm border border-indigo-100 md:col-span-2 lg:col-span-2">
                 <div className="flex justify-between items-start mb-4">
                    <div>
                      <h3 className="font-bold text-gray-800 flex items-center gap-2">
                        <Dumbbell className="text-indigo-500" size={20}/> Proteína
                      </h3>
                      <div className="flex items-baseline gap-1 mt-1">
                        <span className="text-2xl font-bold text-indigo-600">{totals.protein}g</span>
                        <span className="text-sm text-gray-400">/ {targets.protein}g meta</span>
                      </div>
                    </div>
                    {totals.protein >= targets.protein && (
                      <span className="bg-green-100 text-green-700 text-xs px-2 py-1 rounded-full font-bold">Meta Cumplida</span>
                    )}
                 </div>

                 {/* Input Tabs */}
                 <div className="bg-gray-50 p-1 rounded-lg flex text-sm mb-3">
                   <button 
                     onClick={() => setProteinMode('grams')}
                     className={`flex-1 py-1.5 rounded-md transition-all ${proteinMode === 'grams' ? 'bg-white shadow text-indigo-600 font-medium' : 'text-gray-500 hover:text-gray-700'}`}
                   >
                     Manual (g)
                   </button>
                   <button 
                     onClick={() => setProteinMode('food')}
                     className={`flex-1 py-1.5 rounded-md transition-all ${proteinMode === 'food' ? 'bg-white shadow text-indigo-600 font-medium' : 'text-gray-500 hover:text-gray-700'}`}
                   >
                     Comida (IA)
                   </button>
                 </div>

                 <div className="flex gap-2">
                   {proteinMode === 'grams' ? (
                     <input 
                       type="number" 
                       placeholder="Gramos..."
                       value={proteinInput}
                       onChange={(e) => setProteinInput(e.target.value)}
                       className="flex-1 border border-gray-200 rounded-lg px-3 py-2 outline-none focus:border-indigo-500"
                     />
                   ) : (
                     <input 
                       type="text" 
                       placeholder="Ej: 2 huevos y pan"
                       value={foodInput}
                       onChange={(e) => setFoodInput(e.target.value)}
                       className="flex-1 border border-gray-200 rounded-lg px-3 py-2 outline-none focus:border-indigo-500"
                     />
                   )}
                   <button 
                     onClick={handleProteinSubmit}
                     disabled={estimatingProtein}
                     className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 rounded-lg font-medium transition-colors disabled:bg-indigo-300"
                   >
                     {estimatingProtein ? <Sparkles className="animate-spin" size={18}/> : <Plus size={20} />}
                   </button>
                 </div>
                 {proteinLeft > 0 && (
                   <p className="text-xs text-gray-400 mt-2">Te faltan {proteinLeft}g. ¡Sigue así!</p>
                 )}
              </div>
            );
          }

          // CREATINE WIDGET
          if (suppId === 'creat') {
            const hasTaken = totals.creatine > 0;
            return (
              <div key={suppId} className={`p-5 rounded-xl shadow-sm border transition-all ${hasTaken ? 'bg-green-50 border-green-200' : 'bg-white border-gray-100'}`}>
                <div className="flex justify-between items-start">
                   <h3 className="font-bold text-gray-800 flex items-center gap-2">
                     <Zap className={hasTaken ? "text-green-500" : "text-yellow-500"} size={20}/> Creatina
                   </h3>
                   {hasTaken && <Check className="text-green-600" size={24} />}
                </div>

                <p className="text-sm text-gray-500 mt-2 mb-4">
                  {hasTaken 
                    ? "¡Excelente! Has cumplido con tu creatina hoy." 
                    : "No olvides tu dosis diaria para mantener la saturación."}
                </p>

                {!hasTaken ? (
                  <button 
                    onClick={toggleCreatine}
                    className="w-full bg-yellow-50 hover:bg-yellow-100 text-yellow-700 border border-yellow-200 font-medium py-2 rounded-lg flex items-center justify-center gap-2"
                  >
                    Hoy consumí Creatina ({supp.defaultAmount}g)
                  </button>
                ) : (
                  <div className="text-xs text-green-700 bg-green-100/50 p-2 rounded">
                    Recuerda: Tu meta de agua aumentó hoy.
                  </div>
                )}
              </div>
            );
          }

          // GENERIC WIDGET (Magnesium, Omega 3, Custom, etc)
          const isTaken = todaysLogs.some(l => l.name === supp.name && l.type === supp.type);
          const isCustom = suppId.startsWith('custom-');

          return (
            <div key={suppId} className={`p-5 rounded-xl shadow-sm border transition-all ${isTaken ? 'bg-gray-50 border-gray-200 opacity-75' : 'bg-white border-gray-100'} ${isCustom ? 'border-indigo-100' : ''}`}>
              <div className="flex justify-between items-start mb-2">
                 <div>
                   <h3 className="font-bold text-gray-800">{supp.name}</h3>
                   {isCustom && <span className="text-[10px] text-indigo-500 bg-indigo-50 px-1 rounded">Personalizado</span>}
                 </div>
                 {isTaken && <Check className="text-green-600" size={20} />}
              </div>
              <p className="text-xs text-gray-500 mb-4">{supp.defaultAmount}{supp.defaultUnit} - {supp.description}</p>

              {!isTaken ? (
                <button 
                  onClick={() => handleGenericAdd(suppId)}
                  className="w-full border border-gray-200 hover:bg-gray-50 text-gray-600 font-medium py-2 rounded-lg text-sm"
                >
                  Registrar toma
                </button>
              ) : (
                <div className="w-full text-center text-xs font-semibold text-green-600 py-2">
                  Registrado ✓
                </div>
              )}
            </div>
          );
        })}

        {/* AI Insight Card (Always visible at bottom or end) */}
        <div className="bg-gradient-to-br from-purple-50 to-white p-5 rounded-xl shadow-sm border border-purple-100 md:col-span-2 lg:col-span-3">
          <div className="flex justify-between items-center mb-3">
             <div className="flex items-center gap-2">
                <Sparkles size={20} className="text-purple-500" />
                <h3 className="font-bold text-gray-800">Coach IA - Análisis Diario</h3>
             </div>
             {!aiAnalysis && (
               <button 
                 onClick={handleGetAnalysis} 
                 disabled={loadingAi}
                 className="text-xs bg-purple-600 hover:bg-purple-700 text-white px-4 py-1.5 rounded-full transition-colors shadow-sm"
               >
                 {loadingAi ? "Analizando..." : "Analizar mi día"}
               </button>
             )}
          </div>
          <div className="text-sm text-gray-600 min-h-[40px]">
            {loadingAi ? (
               <div className="animate-pulse flex space-x-4">
                 <div className="flex-1 space-y-2 py-1">
                   <div className="h-2 bg-purple-200 rounded"></div>
                   <div className="h-2 bg-purple-200 rounded w-5/6"></div>
                 </div>
               </div>
            ) : aiAnalysis ? (
              <p className="italic border-l-4 border-purple-300 pl-3">"{aiAnalysis}"</p>
            ) : (
              <p>Presiona analizar para recibir feedback sobre tu hidratación y macros de hoy.</p>
            )}
          </div>
        </div>

      </div>
    );
  };

  return (
    <div className="space-y-6">
      {/* Welcome Banner */}
      <div className="bg-gradient-to-r from-indigo-600 to-purple-600 rounded-2xl p-6 text-white shadow-lg">
        <h1 className="text-2xl font-bold mb-2">Hola, {profile.name} 👋</h1>
        <p className="opacity-90">Administra tu stack diario.</p>
      </div>

      {renderActiveStack()}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { SupplementInfo, UserProfile, SupplementLog, AVAILABLE_SUPPLEMENTS } from '../types';
import { Plus, Info, Check, Sparkles, AlertTriangle } from 'lucide-react';
import { getComplementaryAdvice } from '../services/geminiService';

interface Props {
  onAddLog: (log: Omit<SupplementLog, 'id' | 'timestamp'>) => void;
  userProfile: UserProfile;
}

export const SupplementLogger: React.FC<Props> = ({ onAddLog, userProfile }) => {
  const [selectedSupp, setSelectedSupp] = useState<SupplementInfo | null>(null);
  const [amount, setAmount] = useState<number>(0);
  const [advice, setAdvice] = useState<string | null>(null);
  const [loadingAdvice, setLoadingAdvice] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);

  // Combine built-in and custom supplements for display
  const allSupplements = useMemo(() => {
    return [...AVAILABLE_SUPPLEMENTS, ...(userProfile.customSupplements || [])];
  }, [userProfile.customSupplements]);

  const handleSelect = (supp: SupplementInfo) => {
    setSelectedSupp(supp);
    setAmount(supp.defaultAmount);
    setAdvice(null);
    setShowSuccess(false);
  };

  const handleAdd = () => {
    if (selectedSupp) {
      onAddLog({
        name: selectedSupp.name,
        type: selectedSupp.type,
        amount: amount,
        unit: selectedSupp.defaultUnit
      });
      setShowSuccess(true);
      setTimeout(() => setShowSuccess(false), 3000);
    }
  };

  const fetchAdvice = async () => {
    if (!selectedSupp) return;
    setLoadingAdvice(true);
    const text = await getComplementaryAdvice(selectedSupp.name, userProfile);
    setAdvice(text);
    setLoadingAdvice(false);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
      {/* Selection Area */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
        <h2 className="text-xl font-bold mb-4 text-gray-800">Registrar Ingesta</h2>
        <div className="grid grid-cols-2 gap-3 mb-6">
          {allSupplements.map((supp) => {
             // Optional: Highlight supplements selected in profile
             const isPreferred = (userProfile.activeSupplements || []).includes(supp.id);
             const isCustom = supp.id.startsWith('custom-');

             return (
              <button
                key={supp.id}
                onClick={() => handleSelect(supp)}
                className={`p-3 rounded-lg text-left transition-all border relative ${
                  selectedSupp?.id === supp.id
                    ? 'bg-indigo-50 border-indigo-500 ring-1 ring-indigo-500'
                    : isPreferred 
                       ? 'bg-gray-50 border-indigo-100' // Subtle highlight for preferred
                       : 'bg-gray-50 border-transparent hover:bg-gray-100'
                }`}
              >
                {isPreferred && <div className="absolute top-1 right-1 w-2 h-2 bg-indigo-400 rounded-full"></div>}
                <span className="block font-medium text-gray-900 truncate pr-2">
                  {supp.name}
                  {isCustom && <span className="ml-1 text-[9px] bg-purple-100 text-purple-700 px-1 rounded">IA</span>}
                </span>
                <span className="text-xs text-gray-500">{supp.defaultAmount}{supp.defaultUnit}</span>
              </button>
            );
          })}
        </div>

        {selectedSupp && (
          <div className="animate-fade-in space-y-4 bg-gray-50 p-4 rounded-lg border border-gray-200">
             <div className="flex justify-between items-center">
                <label className="font-medium text-gray-700">Cantidad ({selectedSupp.defaultUnit})</label>
                <div className="flex items-center gap-3">
                   <button 
                     onClick={() => setAmount(prev => Math.max(0, prev - (selectedSupp.defaultAmount / 2)))}
                     className="w-8 h-8 rounded-full bg-white border border-gray-300 flex items-center justify-center text-gray-600 hover:bg-gray-50"
                   >-</button>
                   <span className="w-16 text-center font-bold text-lg">{amount}</span>
                   <button 
                     onClick={() => setAmount(prev => prev + (selectedSupp.defaultAmount / 2))}
                     className="w-8 h-8 rounded-full bg-white border border-gray-300 flex items-center justify-center text-gray-600 hover:bg-gray-50"
                   >+</button>
                </div>
             </div>

             <button
               onClick={handleAdd}
               className={`w-full py-3 rounded-lg font-bold flex items-center justify-center gap-2 transition-all ${
                 showSuccess 
                   ? 'bg-green-500 text-white'
                   : 'bg-indigo-600 text-white hover:bg-indigo-700'
               }`}
             >
               {showSuccess ? (
                 <><Check size={20}/> Registrado</>
               ) : (
                 <><Plus size={20}/> Agregar al Registro</>
               )}
             </button>
          </div>
        )}
      </div>

      {/* Info / Advice Area */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
        <div className="flex items-center gap-2 mb-4 text-indigo-600">
          <Info size={24} />
          <h2 className="text-xl font-bold">Información y Complementos</h2>
        </div>

        {!selectedSupp ? (
          <div className="h-48 flex items-center justify-center text-gray-400 text-sm text-center px-8">
            Selecciona un suplemento para ver detalles y recomendaciones personalizadas.
          </div>
        ) : (
          <div className="space-y-4">
             {selectedSupp.riskLevel === 'high' && (
              <div className="bg-red-50 p-3 rounded-lg border border-red-200 text-sm text-red-800 flex gap-2">
                <AlertTriangle className="shrink-0" size={18} />
                <strong>Atención Profesional Requerida:</strong> Este suplemento tiene fuertes efectos fisiológicos. Asegúrate de que su uso esté supervisado por un especialista.
              </div>
            )}

            <p className="text-gray-600">{selectedSupp.description}</p>

            {!advice ? (
              <button
                onClick={fetchAdvice}
                disabled={loadingAdvice}
                className="text-sm text-indigo-600 font-medium hover:text-indigo-800 underline decoration-indigo-200 underline-offset-4"
              >
                {loadingAdvice ? "Consultando a Gemini..." : "¿Qué complementa bien a esto? (Preguntar a IA)"}
              </button>
            ) : (
              <div className="bg-indigo-50 p-4 rounded-lg border border-indigo-100 text-sm text-gray-700">
                 <h4 className="font-semibold text-indigo-800 mb-2 flex items-center gap-2">
                   <Sparkles size={14} /> Recomendación de Gemini
                 </h4>
                 <div className="prose prose-sm max-w-none text-gray-700 whitespace-pre-line">
                   {advice}
                 </div>
              </div>
            )}

            {/* Hardcoded specific logic */}
            {selectedSupp.type === 'creatine' && (
              <div className="bg-cyan-50 p-3 rounded-lg border border-cyan-100 text-sm text-cyan-800">
                <strong>💧 Recordatorio de Hidratación:</strong> Para tu peso de {userProfile.weight}kg, deberías consumir al menos {((userProfile.weight * 0.035) + 0.5).toFixed(1)}L de agua hoy si tomas creatina.
              </div>
            )}
             {selectedSupp.type === 'protein' && (
              <div className="bg-orange-50 p-3 rounded-lg border border-orange-100 text-sm text-orange-800">
                <strong>🥩 Tip de Proteína:</strong> Recuerda distribuir tu ingesta a lo largo del día para maximizar la absorción.
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { UserProfile, SupplementLog, DailyTargets } from './types';
import { LayoutDashboard, PlusCircle, Settings, Dumbbell } from 'lucide-react';
import { Dashboard } from './components/Dashboard';
import { SupplementLogger } from './components/SupplementLogger';
import { ProfileSettings } from './components/ProfileSettings';

const App: React.FC = () => {
  // --- State ---
  const [activeTab, setActiveTab] = useState<'dashboard' | 'log' | 'profile'>('dashboard');

  const [userProfile, setUserProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('suplemente_profile');
    const defaultProfile: UserProfile = {
      name: 'Atleta',
      weight: 75,
      goal: 'muscle',
      activityLevel: 'moderate',
      activeSupplements: [], // Default empty stack
      customSupplements: [], // Default empty custom
      sleepGoal: 8 // Default
    };

    if (saved) {
      const parsed = JSON.parse(saved);
      // Merge with default to ensure new fields like activeSupplements/customSupplements exist if loading old data
      return { ...defaultProfile, ...parsed };
    }
    return defaultProfile;
  });

  const [logs, setLogs] = useState<SupplementLog[]>(() => {
    const saved = localStorage.getItem('suplemente_logs');
    return saved ? JSON.parse(saved) : [];
  });

  // --- Effects ---
  useEffect(() => {
    localStorage.setItem('suplemente_profile', JSON.stringify(userProfile));
  }, [userProfile]);

  useEffect(() => {
    localStorage.setItem('suplemente_logs', JSON.stringify(logs));
  }, [logs]);

  // --- Calculations ---
  const targets = useMemo<DailyTargets>(() => {
    let proteinMultiplier = 1.6; // Base for active
    if (userProfile.goal === 'muscle') proteinMultiplier = 2.0;
    if (userProfile.activityLevel === 'athlete') proteinMultiplier = 2.2;
    if (userProfile.activityLevel === 'sedentary') proteinMultiplier = 1.0;

    const proteinTarget = Math.round(userProfile.weight * proteinMultiplier);
    const waterTarget = parseFloat((userProfile.weight * 0.035).toFixed(1)); // 35ml per kg base

    return {
      protein: proteinTarget,
      water: waterTarget,
      creatine: 5, // Standard
      sleep: userProfile.sleepGoal || 8
    };
  }, [userProfile]);

  // --- Handlers ---
  const handleAddLog = (logData: Omit<SupplementLog, 'id' | 'timestamp'>) => {
    const newLog: SupplementLog = {
      ...logData,
      id: Date.now().toString(),
      timestamp: Date.now()
    };
    setLogs(prev => [newLog, ...prev]);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row max-w-7xl mx-auto">

      {/* Sidebar Navigation (Desktop) / Bottom Bar (Mobile) */}
      <nav className="md:w-64 bg-white md:min-h-screen border-r border-gray-200 flex flex-row md:flex-col sticky top-0 md:relative z-10 shadow-sm md:shadow-none order-2 md:order-1">
        <div className="hidden md:flex items-center gap-2 p-6 text-indigo-600">
          <Dumbbell size={32} />
          <span className="text-2xl font-bold tracking-tight">SupleSuite</span>
        </div>

        <div className="flex-1 flex md:flex-col justify-around md:justify-start p-2 md:p-4 gap-2">
          <button
            onClick={() => setActiveTab('dashboard')}
            className={`flex items-center gap-3 p-3 rounded-xl transition-all w-full ${
              activeTab === 'dashboard' 
                ? 'bg-indigo-50 text-indigo-600 font-semibold' 
                : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            <LayoutDashboard size={24} />
            <span className="hidden md:block">Resumen</span>
          </button>

          <button
            onClick={() => setActiveTab('log')}
            className={`flex items-center gap-3 p-3 rounded-xl transition-all w-full ${
              activeTab === 'log' 
                ? 'bg-indigo-50 text-indigo-600 font-semibold' 
