import React, { useState, useMemo } from 'react';
import { SupplementLog } from '../types';
import { ChevronLeft, ChevronRight, Calendar as CalendarIcon, Clock, Droplets, Dumbbell, Zap } from 'lucide-react';

interface Props {
  logs: SupplementLog[];
}

export const CalendarHistory: React.FC<Props> = ({ logs }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());

  // Helper to check if two dates are the same day
  const isSameDay = (d1: Date, d2: Date) => {
    return (
      d1.getFullYear() === d2.getFullYear() &&
      d1.getMonth() === d2.getMonth() &&
      d1.getDate() === d2.getDate()
    );
  };

  // Get data for the selected date
  const selectedDayLogs = useMemo(() => {
    return logs.filter(log => isSameDay(new Date(log.timestamp), selectedDate)).sort((a, b) => b.timestamp - a.timestamp);
  }, [logs, selectedDate]);

  // Calendar Logic
  const daysInMonth = new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 0).getDate();
  const firstDayOfMonth = new Date(currentDate.getFullYear(), currentDate.getMonth(), 1).getDay(); // 0 = Sunday

  const prevMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
  };

  const nextMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
  };

  const monthNames = [
    "Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio",
    "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"
  ];

  const renderCalendarCells = () => {
    const cells = [];
    const today = new Date();

    // Padding for days before the 1st of the month
    for (let i = 0; i < firstDayOfMonth; i++) {
      cells.push(<div key={`empty-${i}`} className="h-10 w-10 md:h-14 md:w-14"></div>);
    }

    // Days of the month
    for (let day = 1; day <= daysInMonth; day++) {
      const dateToCheck = new Date(currentDate.getFullYear(), currentDate.getMonth(), day);
      const isToday = isSameDay(dateToCheck, today);
      const isSelected = isSameDay(dateToCheck, selectedDate);

      // Check if this day has logs
      const hasLogs = logs.some(log => isSameDay(new Date(log.timestamp), dateToCheck));

      cells.push(
        <button
          key={day}
          onClick={() => setSelectedDate(dateToCheck)}
          className={`h-10 w-10 md:h-14 md:w-14 rounded-full flex flex-col items-center justify-center relative transition-all
            ${isSelected ? 'bg-indigo-600 text-white shadow-md' : 'hover:bg-indigo-50 text-gray-700'}
            ${isToday && !isSelected ? 'border-2 border-indigo-600 font-bold' : ''}
          `}
        >
          <span className="text-sm md:text-base">{day}</span>
          {hasLogs && !isSelected && (
            <span className="absolute bottom-1 w-1.5 h-1.5 bg-indigo-500 rounded-full"></span>
          )}
          {hasLogs && isSelected && (
             <span className="absolute bottom-1 w-1.5 h-1.5 bg-white/50 rounded-full"></span>
          )}
        </button>
      );
    }

    return cells;
  };

  const getIconForType = (type: string) => {
    switch (type) {
      case 'water': return <Droplets size={16} className="text-cyan-500"/>;
      case 'protein': return <Dumbbell size={16} className="text-indigo-500"/>;
      case 'creatine': return <Zap size={16} className="text-yellow-500"/>;
      default: return <div className="w-4 h-4 rounded-full bg-gray-300"></div>;
    }
  };

  return (
    <div className="space-y-6 animate-fade-in">
       {/* Calendar Card */}
       <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
         <div className="flex justify-between items-center mb-6">
           <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
             <CalendarIcon size={24} className="text-indigo-600"/> 
             Historial
           </h2>
           <div className="flex items-center gap-2 bg-gray-50 rounded-lg p-1">
             <button onClick={prevMonth} className="p-1 hover:bg-white hover:shadow rounded-md transition-all text-gray-600">
               <ChevronLeft size={20} />
             </button>
             <span className="w-32 text-center font-medium text-gray-700">
               {monthNames[currentDate.getMonth()]} {currentDate.getFullYear()}
             </span>
             <button onClick={nextMonth} className="p-1 hover:bg-white hover:shadow rounded-md transition-all text-gray-600">
               <ChevronRight size={20} />
             </button>
           </div>
         </div>

         {/* Weekday Headers */}
         <div className="grid grid-cols-7 mb-2 text-center">
           {['D', 'L', 'M', 'M', 'J', 'V', 'S'].map((d, i) => (
             <span key={i} className="text-xs font-semibold text-gray-400 py-2">{d}</span>
           ))}
         </div>

         {/* Days Grid */}
         <div className="grid grid-cols-7 place-items-center gap-y-1 md:gap-y-2">
           {renderCalendarCells()}
         </div>
       </div>

       {/* Daily Details */}
       <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
         <h3 className="text-lg font-bold text-gray-800 mb-4 border-b border-gray-100 pb-2">
           Resumen: {selectedDate.toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
         </h3>

         {selectedDayLogs.length === 0 ? (
           <div className="text-center py-8 text-gray-400">
             <p>No hay registros para este día.</p>
           </div>
         ) : (
           <div className="space-y-3">
             {selectedDayLogs.map(log => (
               <div key={log.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg border border-gray-100">
                 <div className="flex items-center gap-3">
                   <div className="bg-white p-2 rounded-full shadow-sm">
                      {getIconForType(log.type)}
                   </div>
                   <div>
                     <p className="font-semibold text-gray-800">{log.name}</p>
                     <p className="text-xs text-gray-500 flex items-center gap-1">
                       <Clock size={12} />
                       {new Date(log.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                     </p>
                   </div>
                 </div>
                 <span className="font-mono font-bold text-indigo-600">
                   {log.amount}{log.unit}
                 </span>
               </div>
             ))}
           </div>
         )}
       </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { UserProfile, SupplementLog, DailyTargets } from './types';
import { LayoutDashboard, PlusCircle, Settings, Dumbbell, Calendar } from 'lucide-react';
import { Dashboard } from './components/Dashboard';
import { SupplementLogger } from './components/SupplementLogger';
import { ProfileSettings } from './components/ProfileSettings';
import { CalendarHistory } from './components/CalendarHistory';

const App: React.FC = () => {
  // --- State ---
  const [activeTab, setActiveTab] = useState<'dashboard' | 'log' | 'calendar' | 'profile'>('dashboard');

  const [userProfile, setUserProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('suplemente_profile');
    const defaultProfile: UserProfile = {
      name: 'Atleta',
      weight: 75,
      goal: 'muscle',
      activityLevel: 'moderate',
      activeSupplements: [], // Default empty stack
      customSupplements: [], // Default empty custom
      sleepGoal: 8 // Default
    };

    if (saved) {
      const parsed = JSON.parse(saved);
      // Merge with default to ensure new fields like activeSupplements/customSupplements exist if loading old data
      return { ...defaultProfile, ...parsed };
    }
    return defaultProfile;
  });

  const [logs, setLogs] = useState<SupplementLog[]>(() => {
    const saved = localStorage.getItem('suplemente_logs');
    return saved ? JSON.parse(saved) : [];
  });

  // --- Effects ---
  useEffect(() => {
    localStorage.setItem('suplemente_profile', JSON.stringify(userProfile));
  }, [userProfile]);

  useEffect(() => {
    localStorage.setItem('suplemente_logs', JSON.stringify(logs));
  }, [logs]);

  // --- Calculations ---
  const targets = useMemo<DailyTargets>(() => {
    let proteinMultiplier = 1.6; // Base for active
    if (userProfile.goal === 'muscle') proteinMultiplier = 2.0;
    if (userProfile.activityLevel === 'athlete') proteinMultiplier = 2.2;
    if (userProfile.activityLevel === 'sedentary') proteinMultiplier = 1.0;

    const proteinTarget = Math.round(userProfile.weight * proteinMultiplier);
    const waterTarget = parseFloat((userProfile.weight * 0.035).toFixed(1)); // 35ml per kg base

    return {
      protein: proteinTarget,
      water: waterTarget,
      creatine: 5, // Standard
      sleep: userProfile.sleepGoal || 8
    };
  }, [userProfile]);

  // --- Handlers ---
  const handleAddLog = (logData: Omit<SupplementLog, 'id' | 'timestamp'>) => {
    const newLog: SupplementLog = {
      ...logData,
      id: Date.now().toString(),
      timestamp: Date.now()
    };
    setLogs(prev => [newLog, ...prev]);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row max-w-7xl mx-auto">

      {/* Sidebar Navigation (Desktop) / Bottom Bar (Mobile) */}
      <nav className="md:w-64 bg-white md:min-h-screen border-r border-gray-200 flex flex-row md:flex-col sticky top-0 md:relative z-10 shadow-sm md:shadow-none order-2 md:order-1">
        <div className="hidden md:flex items-center gap-2 p-6 text-indigo-600">
          <Dumbbell size={32} />
          <span className="text-2xl font-bold tracking-tight">SupleMente</span>
        </div>

        <div className="flex-1 flex md:flex-col justify-around md:justify-start p-2 md:p-4 gap-2">
          <button
            onClick={() => setActiveTab('dashboard')}
            className={`flex items-center gap-3 p-3 rounded-xl transition-all w-full ${
              activeTab === 'dashboard' 
                ? 'bg-indigo-50 text-indigo-600 font-semibold' 
                : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            <LayoutDashboard size={24} />
            <span className="hidden md:block">Resumen</span>
          </button>

          <button
            onClick={() => setActiveTab('log')}
            className={`flex items-center gap-3 p-3 rounded-xl transition-all w-full ${
              activeTab === 'log' 
                ? 'bg-indigo-50 text-indigo-600 font-semibold' 
                : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            <PlusCircle size={24} />
            <span className="hidden md:block">Registrar</span>
          </button>

           <button
            onClick={() => setActiveTab('calendar')}
            className={`flex items-center gap-3 p-3 rounded-xl transition-all w-full ${
              activeTab === 'calendar' 
                ? 'bg-indigo-50 text-indigo-600 font-semibold' 
                : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            <Calendar size={24} />
            <span className="hidden md:block">Historial</span>
          </button>

          <button
            onClick={() => setActiveTab('profile')}
            className={`flex items-center gap-3 p-3 rounded-xl transition-all w-full ${
              activeTab === 'profile' 
                ? 'bg-indigo-50 text-indigo-600 font-semibold' 
                : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            <Settings size={24} />
            <span className="hidden md:block">Perfil</span>
          </button>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto order-1 md:order-2">
        {/* Mobile Header */}
        <div className="md:hidden flex items-center gap-2 mb-6 text-indigo-600">
          <Dumbbell size={28} />
          <span className="text-xl font-bold">SupleMente</span>
        </div>

        {activeTab === 'dashboard' && (
          <Dashboard 
            profile={userProfile} 
            logs={logs} 
            targets={targets}
            onAddLog={handleAddLog}
          />
        )}

        {activeTab === 'log' && (
          <SupplementLogger 
            onAddLog={handleAddLog} 
            userProfile={userProfile} 
          />
        )}

        {activeTab === 'calendar' && (
          <CalendarHistory 
            logs={logs}
          />
        )}

        {activeTab === 'profile' && (
          <ProfileSettings 
            profile={userProfile} 
            onSave={(p) => {
              setUserProfile(p);
              setActiveTab('dashboard');
            }} 
          />
        )}
      </main>
    </div>
  );
};

export default App;
